3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	
7	const basePriceOf = (item: Item): number => {
8	  if (item.type === "sword") return 100;
9	  if (item.type === "amulet") return 60;
10	  return 0;
11	};
12	
13	const quotePremium = (items: Item[]): number =>
14	  items.reduce((sum, item) => sum + basePriceOf(item), 0) + PROCESSING_FEE;
15	
16	export const runScenario = (input: Scenario): { results: { premium: number }[] } => ({
17	  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
18	});
